
.app {
  width: 100%;
  display: flex;
  flex-direction: column;
  min-height: 100%;
  background: var(--bg);
}

.app-body {
  display: flex;
  flex: 1;
  min-height: 0;
}

.side-nav {
  display: none;
  flex-direction: column;
  gap: 1px;
  background: var(--nav);
  border-right: 2px solid var(--border);
  width: 68px;
  padding: 10px 2px;
  flex-shrink: 0;

  @media (min-width: 768px) {
    display: flex;
  }
}

.nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1px;
  padding: 10px 2px;
  cursor: pointer;
  border-radius: 3px;
  font-size: 10px;
  color: var(--text-secondary);
  text-align: center;
  transition: all 0.15s;
  border: 1px solid transparent;
  background: none;
  font-family: var(--font-body);

  .nav-icon {
    font-size: 20px;
    line-height: 1;
  }

  &.active {
    background: var(--bg);
    color: var(--accent);
    border-color: var(--border);
  }
}

.main-content {
  flex: 1;
  overflow-y: auto;
  padding: 14px;
}

.bottom-bar {
  display: flex;
  justify-content: space-around;
  background: var(--nav);
  border-top: 2px solid var(--border);
  flex-shrink: 0;

  @media (min-width: 768px) {
    display: none;
  }
}

.tab-btn {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1px;
  padding: 7px 0;
  cursor: pointer;
  font-size: 10px;
  color: var(--text-secondary);
  border: none;
  background: none;
  font-family: var(--font-body);
  transition: all 0.15s;

  .tab-icon {
    font-size: 18px;
  }

  &.active {
    color: var(--accent);
    box-shadow: inset 0 -3px 0 var(--accent);
  }
}
